    border-bottom: 2px solid var(--jlp-border);
}

.jetlag-planner .daily-item {
    display: flex;
    gap: 1rem;
    padding: 1rem;
    margin-bottom: 0.5rem;
    border-radius: var(--jlp-radius-sm);
    border-left: 4px solid var(--jlp-border);
    transition: all var(--jlp-transition);
}

.jetlag-planner .daily-item:hover {
    filter: brightness(1.1);
}

.jetlag-planner .daily-item.sleep {
    border-left-color: var(--jlp-sleep);
    background: rgba(79, 70, 229, 0.15);
}
.jetlag-planner .daily-item.light-seek {
    border-left-color: var(--jlp-light-seek);
    background: rgba(255, 210, 63, 0.15);
}
.jetlag-planner .daily-item.light-avoid {
    border-left-color: var(--jlp-text-muted);
    background: rgba(107, 107, 138, 0.1);
}
.jetlag-planner .daily-item.caffeine {
    border-left-color: var(--jlp-caffeine);
    background: rgba(0, 212, 170, 0.15);
}
.jetlag-planner .daily-item.melatonin {
    border-left-color: var(--jlp-melatonin);
    background: rgba(192, 132, 252, 0.15);
}
.jetlag-planner .daily-item.nap {
    border-left-color: var(--jlp-nap);
    background: rgba(129, 140, 248, 0.15);
}
.jetlag-planner .daily-item.flight {
    border-left-color: var(--jlp-flight);
    background: rgba(255, 107, 53, 0.2);
}

.jetlag-planner .daily-time {
    min-width: 110px;
    font-size: 0.875rem;
    font-weight: 700;
    color: var(--jlp-text-secondary);
}

.jetlag-planner .daily-activity {
    flex: 1;
}

.jetlag-planner .activity-type {
    display: inline-block;
    padding: 0.25rem 0.625rem;
    border-radius: var(--jlp-radius-xs);
    font-size: 0.6875rem;
    font-weight: 800;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 0.375rem;
}

.jetlag-planner .activity-type.sleep { background: var(--jlp-sleep); color: white; }
.jetlag-planner .activity-type.light-seek { background: var(--jlp-light-seek); color: #1a1a2d; }
.jetlag-planner .activity-type.light-avoid { background: var(--jlp-light-avoid); border: 1px solid var(--jlp-text-muted); }
.jetlag-planner .activity-type.caffeine { background: var(--jlp-caffeine); color: #1a1a2d; }
.jetlag-planner .activity-type.melatonin { background: var(--jlp-melatonin); color: white; }
.jetlag-planner .activity-type.nap { background: var(--jlp-nap); color: white; }
.jetlag-planner .activity-type.flight { background: var(--jlp-flight); color: white; }

.jetlag-planner .activity-description {
    font-size: 0.875rem;
    color: var(--jlp-text-muted);
    line-height: 1.4;
}

/* ============ Legend ============ */

.jetlag-planner .legend {
    display: flex;
    flex-wrap: wrap;
    gap: 0.75rem 1.25rem;
    margin-bottom: 1.25rem;
    padding: 1rem;
    background: var(--jlp-surface-light);
    border-radius: var(--jlp-radius-sm);
    border: 1px solid var(--jlp-border);
}

.jetlag-planner .legend-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--jlp-text-secondary);
}

.jetlag-planner .legend-color {
    width: 14px;
    height: 14px;
    border-radius: 4px;
}

/* ============ Shifter View ============ */

.jetlag-planner .shifter-container {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.jetlag-planner .shifter-day {
    border-bottom: 1px solid var(--jlp-border);
}

.jetlag-planner .shifter-day:last-child {
    border-bottom: none;
}

.jetlag-planner .shifter-day-today {
    background: rgba(255, 59, 92, 0.05);
}

.jetlag-planner .shifter-date-header {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 0;
    background: var(--jlp-surface-light);
    border-bottom: 1px solid var(--jlp-border);
    position: sticky;
    top: 0;
    z-index: 5;
}

.jetlag-planner .shifter-date {
    font-weight: 700;
    font-size: 0.875rem;
    color: var(--jlp-text);
}

.jetlag-planner .shifter-label {
    font-size: 0.75rem;
    color: var(--jlp-text-muted);
    flex: 1;
}

.jetlag-planner .shifter-now-badge {
    background: #ff3b5c;
    color: white;
    font-size: 0.625rem;
    font-weight: 700;
    padding: 2px 8px;
    border-radius: 4px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.jetlag-planner .shifter-timeline {
    display: flex;
    position: relative;
    min-height: 200px;
}

.jetlag-planner .shifter-hours-left,
.jetlag-planner .shifter-hours-right {
    display: flex;
    flex-direction: column;
    width: 40px;
    flex-shrink: 0;
}

.jetlag-planner .shifter-hour {
    flex: 1;
    display: flex;
    align-items: flex-start;
    justify-content: center;
    font-size: 0.6875rem;
    font-weight: 600;
    color: var(--jlp-text-muted);
    padding-top: 2px;
    min-height: 30px;
}

.jetlag-planner .shifter-hours-right .shifter-hour {
    color: var(--jlp-text-secondary);
}

.jetlag-planner .shifter-track {
    flex: 1;
    position: relative;
    background: var(--jlp-surface-light);
    border-left: 1px solid var(--jlp-border);
    border-right: 1px solid var(--jlp-border);
    min-height: 200px;
}

.jetlag-planner .shifter-track::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: repeating-linear-gradient(
        to bottom,
        transparent,
        transparent 29px,
        var(--jlp-border) 29px,
        var(--jlp-border) 30px
    );
    pointer-events: none;
}

/* Event bars */
.jetlag-planner .shifter-event {
    position: absolute;
    border-radius: 20px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: transform 0.15s ease, box-shadow 0.15s ease;
    min-width: 36px;
    overflow: hidden;
}

.jetlag-planner .shifter-event:hover {
    transform: scale(1.05);
    z-index: 10;
}

.jetlag-planner .shifter-event.active {
    box-shadow: 0 0 0 3px rgba(255, 59, 92, 0.5);
}

.jetlag-planner .shifter-event-icon {
    font-size: 1rem;
    line-height: 1;
}

.jetlag-planner .shifter-event-sleep {
    background: linear-gradient(180deg, #3b4976 0%, #2d3a5e 100%);
}

.jetlag-planner .shifter-event-nap {
    background: linear-gradient(180deg, #6b7db3 0%, #5a6a9a 100%);
}

.jetlag-planner .shifter-event-light-seek {
    background: linear-gradient(180deg, #f5a623 0%, #e8941e 100%);
}

.jetlag-planner .shifter-event-light-avoid {
    background: linear-gradient(180deg, #f5a623 0%, #e8941e 100%);
    opacity: 0.4;
    border: 2px dashed #f5a623;
}

.jetlag-planner .shifter-event-caffeine {
    background: linear-gradient(180deg, #8b6914 0%, #6d5210 100%);
}

.jetlag-planner .shifter-event-melatonin {
    background: linear-gradient(180deg, #a8b4d4 0%, #8fa0c4 100%);
}

.jetlag-planner .shifter-event-flight {
    background: linear-gradient(180deg, var(--jlp-flight) 0%, #e85a2c 100%);
}

/* Now line */
.jetlag-planner .shifter-now-line {
    position: absolute;
    left: 0;
    right: 0;
    height: 2px;
    z-index: 15;
    display: flex;
    align-items: center;
}

.jetlag-planner .shifter-now-dot {
    width: 10px;
    height: 10px;
    background: #ff3b5c;
    border-radius: 50%;
    margin-left: -5px;
    box-shadow: 0 0 8px rgba(255, 59, 92, 0.6);
}

.jetlag-planner .shifter-now-line-bar {
    flex: 1;
    height: 2px;
    background: #ff3b5c;
}

.jetlag-planner .shifter-now-time {
    background: #ff3b5c;
    color: white;
    font-size: 0.625rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 4px;
    margin-left: 4px;
    white-space: nowrap;
}

/* Popup */
.jetlag-planner .shifter-popup {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: 100;
    pointer-events: none;
    opacity: 0;
    transition: opacity 0.2s ease;
}

.jetlag-planner .shifter-popup.visible {
    opacity: 1;
    pointer-events: auto;
}

.jetlag-planner .shifter-popup-content {
    position: absolute;
    background: var(--jlp-surface-elevated);
    border: 1px solid var(--jlp-border);
    border-radius: var(--jlp-radius-sm);
    padding: 1rem;
    max-width: 280px;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.jetlag-planner .shifter-popup-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
}

.jetlag-planner .shifter-popup-icon {
    font-size: 1.25rem;
}

.jetlag-planner .shifter-popup-title {
    font-weight: 700;
    font-size: 0.9375rem;
    color: var(--jlp-text);
}

.jetlag-planner .shifter-popup-time {
    font-size: 0.8125rem;
    font-weight: 600;
    color: var(--jlp-primary);
    margin-bottom: 0.5rem;
    white-space: pre-line;
    line-height: 1.5;
}

.jetlag-planner .shifter-popup-desc {
    font-size: 0.8125rem;
    color: var(--jlp-text-secondary);
    line-height: 1.4;
}

/* Responsive shifter */
@media (max-width: 400px) {
    .jetlag-planner .shifter-hours-left,
    .jetlag-planner .shifter-hours-right {
        width: 32px;
    }

    .jetlag-planner .shifter-hour {
        font-size: 0.5625rem;
    }

    .jetlag-planner .shifter-event {
        min-width: 28px;
    }

    .jetlag-planner .shifter-event-icon {
        font-size: 0.875rem;
    }
}

/* ============ Utilities ============ */

.jetlag-planner .hidden {
    display: none !important;
}

.jetlag-planner .saved-indicator {
    display: inline-flex;
    align-items: center;
    gap: 0.375rem;
    padding: 0.375rem 0.75rem;
    font-size: 0.6875rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--jlp-secondary);
    background: rgba(0, 212, 170, 0.15);
    border-radius: var(--jlp-radius-xs);
    margin-left: auto;
}

/* ============ Animations ============ */

@keyframes jlp-fadeIn {
    from {
        opacity: 0;
        transform: translateY(16px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes jlp-slideIn {
    from {
        opacity: 0;
        transform: translateX(-8px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

/* WordPress-specific: suppress body-level flex layout */
.jetlag-planner .app-container {
    display: block;
}
