// Populate timezone select elements
// Uses _appRoot (set by app.js initJetLagApp) to scope queries
function populateTimezoneSelects() {
    const root = (typeof _appRoot !== 'undefined' && _appRoot) ? _appRoot : document;
    const selects = root.querySelectorAll('select[id$="-timezone"], select.departure-timezone, select.arrival-timezone');
    selects.forEach(select => {
        if (select.options.length > 1) return; // Already populated

        // Clear and rebuild options using safe DOM methods
        while (select.firstChild) select.removeChild(select.firstChild);
        const defaultOpt = document.createElement('option');
        defaultOpt.value = '';
        defaultOpt.textContent = 'Select timezone...';
        select.appendChild(defaultOpt);

        TIMEZONES.forEach(tz => {
            const option = document.createElement('option');
            option.value = tz.id;
            option.textContent = tz.name;
            option.dataset.offset = tz.offset;
            select.appendChild(option);
        });
    });
}

// Get timezone offset from timezone ID or airport code
// If a date is provided, computes the actual offset for that date (DST-aware)
function getTimezoneOffset(timezoneIdOrAirport, date) {
    // Resolve to IANA timezone ID
    const tzId = resolveTimezoneId(timezoneIdOrAirport);

    // Try dynamic offset if date is provided
    if (date && tzId) {
        const dynamic = getDynamicOffset(tzId, date);
        if (dynamic !== null) return dynamic;
    }

    // Fallback to static offset
    const airport = AIRPORTS[timezoneIdOrAirport.toUpperCase?.() || ''];
    if (airport) return airport.offset;

    const tz = TIMEZONES.find(t => t.id === timezoneIdOrAirport);
    return tz ? tz.offset : null;
}

// Resolve an airport code or timezone ID to an IANA timezone ID
function resolveTimezoneId(timezoneIdOrAirport) {
    if (!timezoneIdOrAirport) return null;
    const airport = AIRPORTS[timezoneIdOrAirport.toUpperCase?.() || ''];
    if (airport) return airport.timezone;
    const tz = TIMEZONES.find(t => t.id === timezoneIdOrAirport);
    return tz ? tz.id : timezoneIdOrAirport; // Assume it's already an IANA ID
}

// Compute the actual UTC offset for a timezone at a specific date (DST-aware)
function getDynamicOffset(timezoneId, date) {
    try {
        const fmt = new Intl.DateTimeFormat('en-US', {
            timeZone: timezoneId,
            timeZoneName: 'longOffset',
        });
        const parts = fmt.formatToParts(date instanceof Date ? date : new Date(date));
        const tzPart = parts.find(p => p.type === 'timeZoneName');
        if (!tzPart) return null;
        if (tzPart.value === 'GMT') return 0;
        const match = tzPart.value.match(/GMT([+-])(\d{1,2}):?(\d{2})?/);
        if (match) {
            const sign = match[1] === '+' ? 1 : -1;
            return sign * (parseInt(match[2]) + parseInt(match[3] || '0') / 60);
        }
        return null;
    } catch (e) {
        return null;
    }
}

// Get timezone from airport code
function getTimezoneFromAirport(code) {
    const airport = AIRPORTS[code.toUpperCase()];
    return airport ? airport.timezone : null;
}

// Auto-detect user's timezone
function detectUserTimezone() {
    try {
        const userTz = Intl.DateTimeFormat().resolvedOptions().timeZone;
        const match = TIMEZONES.find(tz => tz.id === userTz);
        return match ? match.id : 'America/New_York';
    } catch (e) {
        return 'America/New_York';
    }
}

/**
 * JetLag Algorithm
 *
 * Scientific basis:
 * - Core Body Temperature minimum (CBTmin) occurs ~2-3 hours before natural wake time
 * - Light exposure AFTER CBTmin advances circadian clock (for eastward travel)
 * - Light exposure BEFORE CBTmin delays circadian clock (for westward travel)
 * - Body can shift ~1-1.5 hours per day naturally
 * - Melatonin ~1.5h before bed to assist natural rise in melatonin (CDC recommendation)
 * - Caffeine should be avoided 6+ hours before desired sleep
 */

class JetLagPlanner {
    constructor(config) {
        this.homeTimezone = config.homeTimezone;
        this.usualBedtime = this.parseTime(config.usualBedtime); // minutes from midnight
        this.usualWaketime = this.parseTime(config.usualWaketime);
        this.flights = config.flights;
        this.daysBeforeStart = config.daysBeforeStart !== undefined ? config.daysBeforeStart : 2;

        // Compute home offset using first flight date for DST accuracy
        const refDate = this.flights.length > 0 ? new Date(this.flights[0].departureDateTime) : new Date();
        this.homeOffset = getTimezoneOffset(config.homeTimezone, refDate);

        // Constants
        this.MAX_SHIFT_PER_DAY = 1.5; // hours
        this.SLEEP_DURATION = this.calculateSleepDuration();
        this.CBMT_BEFORE_WAKE = 2.5; // hours before wake time
        this.LIGHT_EXPOSURE_DURATION = 2; // hours
        this.CAFFEINE_CUTOFF_BEFORE_BED = 6; // hours
        this.MELATONIN_BEFORE_BED = 1.5; // hours — CDC recommends 90 min before bed
    }

    parseTime(timeStr) {
        const [hours, minutes] = timeStr.split(':').map(Number);
        return hours * 60 + minutes;
    }

    formatTime(minutes) {
        const normalizedMinutes = ((minutes % 1440) + 1440) % 1440;
        const hours = Math.floor(normalizedMinutes / 60);
        const mins = Math.round(normalizedMinutes % 60);
        return `${hours.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}`;
    }

    calculateSleepDuration() {
        let duration = this.usualWaketime - this.usualBedtime;
        if (duration < 0) duration += 1440; // Handle overnight sleep
        return duration;
    }

    /**
     * Calculate true flight duration by converting local times to UTC.
     *
     * The datetime-local input gives us "wall clock" time at departure/arrival,
     * but without timezone info. We need to convert both to UTC to get the
     * actual elapsed time.
     *
     * Example: HNL 9:00 AM (UTC-10) to TYO 5:00 PM next day (UTC+9)
     *   - Departure UTC: 9:00 + 10 = 19:00 on Jan 31
     *   - Arrival UTC: 17:00 - 9 = 08:00 on Feb 1
     *   - Duration: 13 hours (not 32 hours!)
     */
    calculateFlightDuration(flight) {
        const depDate = new Date(flight.departureDateTime);
        const arrDate = new Date(flight.arrivalDateTime);
        const depOffset = getTimezoneOffset(flight.departureTimezone, depDate);
        const arrOffset = getTimezoneOffset(flight.arrivalTimezone, arrDate);

        if (depOffset === null || arrOffset === null) {
            // Fallback to naive calculation if timezones unknown
            const start = new Date(flight.departureDateTime);
            const end = new Date(flight.arrivalDateTime);
            return (end - start) / (1000 * 60);
        }

        // Parse the local times
        const depLocal = new Date(flight.departureDateTime);
        const arrLocal = new Date(flight.arrivalDateTime);

        // Convert to UTC by subtracting the timezone offset
        // (offset is in hours, positive = east of UTC)
        const depUTC = depLocal.getTime() - (depOffset * 60 * 60 * 1000);
        const arrUTC = arrLocal.getTime() - (arrOffset * 60 * 60 * 1000);

        // Duration in minutes
        const durationMins = (arrUTC - depUTC) / (1000 * 60);

        return Math.max(0, durationMins);
    }

    /**
     * Calculate optimal in-flight sleep based on flight duration, arrival time, and direction.
     *
     * Scientific rationale:
     * - Short flights (4-6h): 90-min nap (one sleep cycle) to avoid deep sleep inertia
     * - Medium flights (6-10h): 2-3 hours of sleep, especially if arriving in morning
     * - Long flights (10-14h): 3-4 hours of sleep, timed to align with destination night
     * - Ultra-long flights (14h+): Up to 5-6 hours, essentially a full sleep period
     *
     * Arrival time considerations:
     * - Morning arrival: Sleep more on plane (you'll need to stay awake all day)
     * - Evening arrival: Sleep less on plane (you can sleep soon after landing)
     *
     * Direction considerations:
     * - Eastward: Pre-arrival sleep is more critical (you're losing hours)
     * - Westward: Can get away with less sleep (you're gaining hours)
     */
    calculateInFlightSleep(params) {
        const { flightDurationMins, arrivalTime, direction, arrivalOffset, departureOffset } = params;

        // Get arrival hour in local destination time
        const arrivalHour = arrivalTime.getHours();

        // Determine if arriving in morning (need to stay awake) vs evening (can sleep soon)
        const isMorningArrival = arrivalHour >= 5 && arrivalHour <= 14;
        const isEveningArrival = arrivalHour >= 18 || arrivalHour <= 4;

        const startOffset = 30;  // ~30 min after takeoff (reach cruising altitude)
        const landingBuffer = 60; // Wake up ~1h before landing

        // Sleep as much of the flight as possible, ending 1h before landing
        let finalDuration = flightDurationMins - startOffset - landingBuffer;
        finalDuration = Math.round(finalDuration / 15) * 15; // Round to 15 min

        // Cap at 6h max (a full night's rest) and 90 min minimum (one sleep cycle)
        finalDuration = Math.min(finalDuration, 360);
        finalDuration = Math.max(finalDuration, 90);

        // For evening arrivals, reduce sleep to build sleep pressure for bedtime
        if (isEveningArrival) {
            finalDuration = Math.min(finalDuration, 180);
        }

        // Build description
        let description;
        const hours = Math.floor(finalDuration / 60);
        const mins = finalDuration % 60;
        const timeStr = hours > 0
            ? (mins > 0 ? `${hours}h ${mins}m` : `${hours}h`)
            : `${mins} mins`;

        if (finalDuration >= 180) {
            description = `In-flight sleep (${timeStr}) - ${isMorningArrival ? 'rest up before a full day ahead' : 'helps shift to destination time'}`;
        } else if (finalDuration >= 120) {
            description = `In-flight rest (${timeStr}) - ${isMorningArrival ? 'banking sleep for morning arrival' : 'helps adjust to destination time'}`;
        } else {
            description = `In-flight nap (${timeStr}) - one sleep cycle to refresh`;
        }

        return {
            duration: Math.max(0, Math.round(finalDuration)),
            startOffset,
            description,
        };
    }

    generatePlan() {
        if (this.flights.length === 0) {
            return { error: 'No flights provided' };
        }

        // Sort flights by departure time
        const sortedFlights = [...this.flights].sort((a, b) =>
            new Date(a.departureDateTime) - new Date(b.departureDateTime)
        );

        const firstFlight = sortedFlights[0];
        const lastFlight = sortedFlights[sortedFlights.length - 1];

        // Calculate total timezone shift (DST-aware using actual flight dates)
        const departureOffset = getTimezoneOffset(firstFlight.departureTimezone, new Date(firstFlight.departureDateTime));
        const arrivalOffset = getTimezoneOffset(lastFlight.arrivalTimezone, new Date(lastFlight.arrivalDateTime));
        const totalShift = arrivalOffset - departureOffset; // positive = eastward

        // Determine direction and optimal approach
        let effectiveShift = totalShift;
        let direction = 'east';

        // If shift > 12 hours, it may be easier to go the other way
        if (Math.abs(totalShift) > 12) {
            effectiveShift = totalShift > 0 ? totalShift - 24 : totalShift + 24;
        }

        if (effectiveShift < 0) {
            direction = 'west';
            effectiveShift = Math.abs(effectiveShift);
        }

        // Calculate number of days needed for adjustment
        const daysToAdjust = Math.ceil(effectiveShift / this.MAX_SHIFT_PER_DAY);

        // Generate schedule
        const schedule = this.buildSchedule({
            flights: sortedFlights,
            direction,
            totalShift: effectiveShift,
            daysToAdjust,
            departureOffset,
            arrivalOffset,
            firstDepartureDate: new Date(firstFlight.departureDateTime),
            lastArrivalDate: new Date(lastFlight.arrivalDateTime),
        });

        return {
            summary: {
                direction,
                totalShiftHours: effectiveShift,
                daysToAdjust,
                departureTimezone: firstFlight.departureTimezone,
                arrivalTimezone: lastFlight.arrivalTimezone,
                firstDepartureDate: firstFlight.departureDateTime,
                lastArrivalDate: lastFlight.arrivalDateTime,
            },
            schedule,
        };
    }

    buildSchedule(params) {
        const {
            flights,
            direction,
            totalShift,
            daysToAdjust,
            departureOffset,
            arrivalOffset,
            firstDepartureDate,
            lastArrivalDate,
        } = params;

        const schedule = [];

        // Start date: N days before first flight
        const startDate = new Date(firstDepartureDate);
        startDate.setDate(startDate.getDate() - this.daysBeforeStart);
        startDate.setHours(0, 0, 0, 0);

        // End date: schedule should span exactly daysBeforeStart + daysToAdjust days
        const totalScheduleDays = this.daysBeforeStart + daysToAdjust;
        const endDate = new Date(startDate);
        endDate.setDate(startDate.getDate() + totalScheduleDays - 1);
        endDate.setHours(23, 59, 59, 999);

        // Calculate daily shift amount
        const shiftPerDay = totalShift / (this.daysBeforeStart + daysToAdjust);

        // Track current circadian phase (in home timezone initially)
        let currentBedtime = this.usualBedtime;
        let currentWaketime = this.usualWaketime;
        let currentOffset = departureOffset;
        let dayIndex = 0;

        // Determine which phase we're in
        const getPhase = (date) => {
            if (date < firstDepartureDate) return 'pre-flight';
            if (date > lastArrivalDate) return 'post-arrival';
            return 'in-transit';
        };

        // Create flight lookup for blocking times
        // Include pre-calculated duration using proper timezone conversion
        const flightBlocks = flights.map(f => {
            const start = new Date(f.departureDateTime);
            const durationMins = this.calculateFlightDuration(f);
            return {
                start,
                end: new Date(f.arrivalDateTime),
                // Actual end = departure + duration (correct for date-line crossings
                // where wall-clock arrival appears "before" departure)
                actualEnd: new Date(start.getTime() + durationMins * 60 * 1000),
                flight: f,
                durationMins,
            };
        });

        // Check if a time range conflicts with any flight
        const conflictsWithFlight = (start, end) => {
            return flightBlocks.some(fb => {
                return (start < fb.actualEnd && end > fb.start);
            });
        };

        // Iterate through each day
        let currentDate = new Date(startDate);
        while (currentDate <= endDate) {
            const phase = getPhase(currentDate);
            const dayOfTrip = dayIndex - this.daysBeforeStart;
            const events = [];

            // Calculate target times for this day
            // Linear progression: each day shifts by shiftPerDay, capped at totalShift
            const shiftApplied = Math.min(totalShift, (dayIndex + 1) * shiftPerDay);

            // Apply shift (eastward = earlier times, westward = later times)
            const shiftMinutes = (direction === 'east' ? -1 : 1) * shiftApplied * 60;
            const targetBedtime = this.usualBedtime + shiftMinutes;
            const targetWaketime = this.usualWaketime + shiftMinutes;

            // Calculate CBTmin (2-3 hours before wake time)
            const cbtMin = targetWaketime - (this.CBMT_BEFORE_WAKE * 60);

            // Add flight events for this day
            flightBlocks.forEach(fb => {
                const flightDate = new Date(fb.start);
                const flightStartMins = fb.start.getHours() * 60 + fb.start.getMinutes();
                const flightDurationMins = fb.durationMins;
                const flightEndMins = flightStartMins + flightDurationMins;

                // Get timezone info for display
                const depTz = fb.flight.departureTimezone;
                const arrTz = fb.flight.arrivalTimezone;
                const depOffset = getTimezoneOffset(depTz, fb.start);
                const arrOffset = getTimezoneOffset(arrTz, fb.end);
                const tzShift = arrOffset - depOffset;

                // Format arrival time in arrival timezone for description
                const arrivalLocalTime = fb.end.getHours() * 60 + fb.end.getMinutes();
                const arrivalTimeStr = this.formatTime(arrivalLocalTime);

                const flightDesc = `Flight: ${fb.flight.departureAirport || 'Departure'} → ${fb.flight.arrivalAirport || 'Arrival'} (${Math.floor(flightDurationMins / 60)}h ${flightDurationMins % 60}m)`;

                // Compute the actual end date/time of the flight
                const flightActualEnd = new Date(fb.start.getTime() + flightDurationMins * 60 * 1000);

                if (flightDate.toDateString() === currentDate.toDateString()) {
                    // Flight departs on this day
                    events.push({
                        type: 'flight',
                        startTime: flightStartMins,
                        endTime: Math.min(flightEndMins, 1440), // Clamp at midnight if overnight
                        description: flightDesc,
                        flight: fb.flight,
                        durationMins: flightDurationMins,
                        departureTimezone: depTz,
                        arrivalTimezone: arrTz,
                        arrivalLocalTime: arrivalTimeStr,
                        timezoneShift: tzShift,
                    });

                    // Add in-flight sleep for longer flights (4+ hours)
                    if (flightDurationMins >= 240) {
                        const sleepParams = this.calculateInFlightSleep({
                            flightDurationMins,
                            arrivalTime: fb.end,
                            direction,
                            arrivalOffset,
                            departureOffset,
                        });

                        if (sleepParams.duration > 0) {
                            const sleepStartMins = flightStartMins + sleepParams.startOffset;
                            const sleepEndMins = sleepStartMins + sleepParams.duration;

                            const sleepEndsBeforeLanding = (sleepParams.startOffset + sleepParams.duration + 30) < flightDurationMins;

                            if (sleepEndsBeforeLanding) {
                                const isLongSleep = sleepParams.duration >= 120;
                                events.push({
                                    type: isLongSleep ? 'sleep' : 'nap',
                                    startTime: sleepStartMins,
                                    endTime: sleepEndMins,
                                    description: sleepParams.description,
                                    inFlight: true,
                                });
                            }
                        }
                    }
                }

                // Check if flight carries over from previous day into this day
                if (flightActualEnd.toDateString() === currentDate.toDateString() &&
                    flightDate.toDateString() !== currentDate.toDateString()) {
                    const endMinsToday = flightActualEnd.getHours() * 60 + flightActualEnd.getMinutes();
                    if (endMinsToday > 0) {
                        events.push({
                            type: 'flight',
                            startTime: 0, // From midnight
                            endTime: endMinsToday,
                            description: flightDesc + ' (cont.)',
                            flight: fb.flight,
                            durationMins: flightDurationMins,
                            departureTimezone: depTz,
                            arrivalTimezone: arrTz,
                            arrivalLocalTime: arrivalTimeStr,
                            timezoneShift: tzShift,
                        });
                    }
                }
            });

            // Sleep event
            events.push({
                type: 'sleep',
                startTime: targetBedtime,
                endTime: targetWaketime,
                description: 'Sleep',
            });

            // Light exposure recommendations
            if (direction === 'east') {
                // Seek light after CBTmin (morning) to advance clock
                const lightSeekStart = Math.max(targetWaketime, cbtMin);
                const lightSeekEnd = lightSeekStart + this.LIGHT_EXPOSURE_DURATION * 60;
                events.push({
                    type: 'light-seek',
                    startTime: lightSeekStart,
                    endTime: lightSeekEnd,
                    description: 'Seek bright light (sunlight or light box)',
                });

                // Avoid light before CBTmin (evening before bed)
                const lightAvoidStart = targetBedtime - 3 * 60;
                const lightAvoidEnd = targetBedtime;
                events.push({
                    type: 'light-avoid',
                    startTime: lightAvoidStart,
                    endTime: lightAvoidEnd,
                    description: 'Avoid bright light, use dim lighting or blue blockers',
                });

                // Melatonin to advance clock (90 min before target bedtime per CDC)
                const melatoninTime = targetBedtime - this.MELATONIN_BEFORE_BED * 60;
                if (melatoninTime > targetWaketime) {
                    events.push({
                        type: 'melatonin',
                        startTime: melatoninTime,
                        endTime: melatoninTime + 30,
                        description: 'Take melatonin (0.5-3mg) to help advance sleep',
                    });
                }
            } else {
                // Westward: delay the clock
                // Seek light before CBTmin (evening) to delay clock
                const lightSeekStart = targetBedtime - 4 * 60;
                const lightSeekEnd = lightSeekStart + this.LIGHT_EXPOSURE_DURATION * 60;
                if (lightSeekEnd < targetBedtime) {
                    events.push({
                        type: 'light-seek',
                        startTime: lightSeekStart,
                        endTime: lightSeekEnd,
                        description: 'Seek bright light to delay sleep',
                    });
                }

                // Avoid light after waking for first few hours
                const lightAvoidEnd = targetWaketime + 2 * 60;
                events.push({
                    type: 'light-avoid',
                    startTime: targetWaketime,
                    endTime: lightAvoidEnd,
                    description: 'Avoid bright morning light, wear sunglasses if needed',
                });

                // Melatonin upon waking can help delay (optional, less common)
                // Skip for simplicity in westward travel
            }

            // Caffeine windows
            const caffeineStart = targetWaketime;
            const caffeineEnd = targetBedtime - this.CAFFEINE_CUTOFF_BEFORE_BED * 60;
            if (caffeineEnd > caffeineStart) {
                events.push({
                    type: 'caffeine',
                    startTime: caffeineStart,
                    endTime: caffeineEnd,
                    description: 'Caffeine OK (coffee, tea). Stop after this window.',
                });
            }

            // Optional strategic nap (if needed and not during flight)
            if (phase === 'post-arrival' || phase === 'in-transit') {
                // Short nap in early afternoon if needed
                const napTime = targetWaketime + 6 * 60; // 6 hours after wake
                const napEnd = napTime + 20; // 20-minute power nap

                // Check if this conflicts with flights
                const napStartDate = new Date(currentDate);
                napStartDate.setHours(Math.floor(napTime / 60), napTime % 60);
                const napEndDate = new Date(currentDate);
                napEndDate.setHours(Math.floor(napEnd / 60), napEnd % 60);

                if (!conflictsWithFlight(napStartDate, napEndDate) && napTime > 0 && napTime < targetBedtime - 4 * 60) {
                    events.push({
                        type: 'nap',
                        startTime: napTime,
                        endTime: napEnd,
                        description: 'Optional 20-min power nap if drowsy (set alarm!)',
                    });
                }
            }

            // Filter out events that conflict with flights (except flights and in-flight activities)
            const filteredEvents = events.filter(event => {
                if (event.type === 'flight') return true;
                if (event.inFlight) return true; // Keep in-flight naps

                // Check if event time conflicts with any flight
                const eventStart = new Date(currentDate);
                const startMins = ((event.startTime % 1440) + 1440) % 1440;
                eventStart.setHours(Math.floor(startMins / 60), startMins % 60);

                const eventEnd = new Date(currentDate);
                const endMins = ((event.endTime % 1440) + 1440) % 1440;
                eventEnd.setHours(Math.floor(endMins / 60), endMins % 60);

                // Handle overnight events
                if (endMins < startMins) {
                    eventEnd.setDate(eventEnd.getDate() + 1);
                }

                return !conflictsWithFlight(eventStart, eventEnd);
            });

            // Convert post-arrival event times to destination timezone
            const isPostArrival = phase === 'post-arrival';
            const tzOffsetMins = (arrivalOffset - departureOffset) * 60;
            if (isPostArrival && tzOffsetMins !== 0) {
                filteredEvents.forEach(event => {
                    if (event.type !== 'flight' && !event.inFlight) {
                        event.startTime += tzOffsetMins;
                        event.endTime += tzOffsetMins;
                    }
                });
            }

            schedule.push({
                date: new Date(currentDate),
                dayIndex,
                dayLabel: this.getDayLabel(dayIndex, this.daysBeforeStart, phase, lastArrivalDate, currentDate),
                phase,
                displayTimezone: isPostArrival ? flights[flights.length - 1].arrivalTimezone : flights[0].departureTimezone,
                events: filteredEvents.sort((a, b) => {
                    const aStart = ((a.startTime % 1440) + 1440) % 1440;
                    const bStart = ((b.startTime % 1440) + 1440) % 1440;
                    return aStart - bStart;
                }),
                targetBedtime: isPostArrival ? targetBedtime + tzOffsetMins : targetBedtime,
                targetWaketime: isPostArrival ? targetWaketime + tzOffsetMins : targetWaketime,
            });

            currentDate.setDate(currentDate.getDate() + 1);
            dayIndex++;
        }

        return schedule;
    }

    getDayLabel(dayIndex, daysBeforeStart, phase, lastArrivalDate, currentDate) {
        if (dayIndex < daysBeforeStart) {
            const daysUntil = daysBeforeStart - dayIndex;
            return `${daysUntil} day${daysUntil > 1 ? 's' : ''} before departure`;
        }

        if (dayIndex === daysBeforeStart) {
            return 'Departure Day';
        }

        // Post-departure: check if this is the arrival date or after
        const arrivalDateOnly = new Date(lastArrivalDate);
        arrivalDateOnly.setHours(0, 0, 0, 0);
        const currentDateOnly = new Date(currentDate);
        currentDateOnly.setHours(0, 0, 0, 0);

        if (currentDateOnly < arrivalDateOnly) {
            return 'Travel Day';
        }

        if (currentDateOnly.getTime() === arrivalDateOnly.getTime()) {
            return 'Arrival Day';
        }

        const daysAfterArrival = Math.round((currentDateOnly - arrivalDateOnly) / (1000 * 60 * 60 * 24));
        return `Day ${daysAfterArrival} at destination`;
    }
}

// Utility function to create planner and generate plan
function createJetLagPlan(config) {
    const planner = new JetLagPlanner(config);
    return planner.generatePlan();
}

/**
 * JetLag Planner - Main Application
 *
 * Scope-aware: all DOM queries go through _appRoot so the app can run
 * standalone (GitHub Pages) or embedded in WordPress.
 */

const STORAGE_KEY = 'jetlag-planner-data';
const URL_PARAM_KEY = 'd'; // Short key for URL param

// Root element for all DOM queries (set by initJetLagApp)
var _appRoot = null;
var _saveTimeout = null;

/**
 * Mount the app inside a given container element.
 * For standalone pages pass the .jetlag-planner wrapper (or document).
 * For WordPress the shortcode wrapper is passed automatically.
 */
function initJetLagApp(rootElement) {
    _appRoot = rootElement || document;
    initializeApp();
}

function initializeApp() {
    // Populate timezone selects
    populateTimezoneSelects();

    // Set default home timezone
    const homeTimezoneSelect = _appRoot.querySelector('#home-timezone');
    const detectedTz = detectUserTimezone();
    if (homeTimezoneSelect) {
        homeTimezoneSelect.value = detectedTz;
    }

    // Try to load saved data - URL takes priority over localStorage
    const urlData = loadFromURL();
    const savedData = urlData || loadFromStorage();

    if (savedData) {
        restoreSavedData(savedData);
        showSavedIndicator(urlData ? 'Loaded from link' : 'Restored');
    } else {
        // Add first flight with defaults
        addFlight();
    }

    // Event listeners
    _appRoot.querySelector('#add-flight-btn').addEventListener('click', () => {
        addFlight();
        saveToStorage();
    });
    _appRoot.querySelector('#generate-btn').addEventListener('click', generatePlan);
    _appRoot.querySelector('#share-btn').addEventListener('click', copyShareLink);

    // Auto-save on input changes (change event for selects/datetime)
    _appRoot.addEventListener('change', (e) => {
        if (e.target.closest('#profile-section, #flights-section, #generate-section')) {
            saveToStorage();
        }
    });

    // Also save on input event for text fields (fires on every keystroke)
    _appRoot.addEventListener('input', (e) => {
        if (e.target.closest('#profile-section, #flights-section, #generate-section')) {
            // Debounce to avoid excessive saves
            clearTimeout(_saveTimeout);
            _saveTimeout = setTimeout(saveToStorage, 500);
        }
    });

    // Save before page unload to catch any unsaved changes
    window.addEventListener('beforeunload', () => {
        saveToStorage();
    });

    // Tab switching
    _appRoot.querySelectorAll('.tab-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            const tabName = e.target.dataset.tab;
            switchTab(tabName);
        });
    });

    // Register service worker (standalone only, not when embedded)
    if (typeof JETLAG_STANDALONE !== 'undefined' && 'serviceWorker' in navigator) {
        navigator.serviceWorker.register('sw.js')
            .then(reg => console.log('Service Worker registered'))
            .catch(err => console.log('Service Worker registration failed:', err));
    }
}

// Auto-init for standalone pages
document.addEventListener('DOMContentLoaded', () => {
    const el = document.querySelector('.jetlag-planner');
    if (el && !_appRoot) initJetLagApp(el);
});

// ============ URL Encoding/Decoding ============

function encodeDataForURL(data) {
    try {
        // Create a minimal data object (exclude savedAt, include only what's needed)
        const minimal = {
            h: data.homeTimezone,           // home timezone
            b: data.usualBedtime,           // bedtime
            w: data.usualWaketime,          // waketime
            d: data.daysBeforeStart,        // days before
            f: data.flights.map(f => ({     // flights (shortened keys)
                da: f.departureAirport,
                aa: f.arrivalAirport,
                dd: f.departureDateTime,
                dt: f.departureTimezone,
                ad: f.arrivalDateTime,
                at: f.arrivalTimezone,
            })),
        };
        const json = JSON.stringify(minimal);
        // Use base64url encoding (URL-safe)
        const base64 = btoa(unescape(encodeURIComponent(json)))
            .replace(/\+/g, '-')
            .replace(/\//g, '_')
            .replace(/=+$/, '');
        return base64;
    } catch (e) {
        console.warn('[JetLag] Could not encode data for URL:', e);
        return null;
    }
}

function decodeDataFromURL(encoded) {
    try {
        // Restore base64 padding and chars
        let base64 = encoded
            .replace(/-/g, '+')
            .replace(/_/g, '/');
        // Add padding if needed
        while (base64.length % 4) {
            base64 += '=';
        }
        const json = decodeURIComponent(escape(atob(base64)));
        const minimal = JSON.parse(json);

        // Expand back to full format
        return {
            homeTimezone: minimal.h,
            usualBedtime: minimal.b,
            usualWaketime: minimal.w,
            daysBeforeStart: minimal.d,
            flights: minimal.f.map(f => ({
                departureAirport: f.da || '',
                arrivalAirport: f.aa || '',
                departureDateTime: f.dd || '',
                departureTimezone: f.dt || '',
                arrivalDateTime: f.ad || '',
                arrivalTimezone: f.at || '',
            })),
        };
    } catch (e) {
        console.warn('[JetLag] Could not decode data from URL:', e);
        return null;
    }
}

function saveToURL(data) {
    const encoded = encodeDataForURL(data);
    if (encoded) {
        const url = new URL(window.location.href);
        url.searchParams.set(URL_PARAM_KEY, encoded);
        // Use replaceState to avoid cluttering browser history
        window.history.replaceState({}, '', url.toString());
        console.log('[JetLag] Saved to URL');
    }
}

function loadFromURL() {
    try {
        const url = new URL(window.location.href);
        const encoded = url.searchParams.get(URL_PARAM_KEY);
        if (encoded) {
            const data = decodeDataFromURL(encoded);
            if (data) {
                console.log('[JetLag] Loaded from URL:', data.flights?.length, 'flights');
                return data;
            }
        }
        return null;
    } catch (e) {
        console.warn('[JetLag] Could not load from URL:', e);
        return null;
    }
}

function getShareableURL() {
    const data = {
        homeTimezone: _appRoot.querySelector('#home-timezone').value,
        usualBedtime: _appRoot.querySelector('#usual-bedtime').value,
        usualWaketime: _appRoot.querySelector('#usual-waketime').value,
        daysBeforeStart: _appRoot.querySelector('#plan-start').value,
        flights: collectFlightData(),
    };
    const encoded = encodeDataForURL(data);
    if (encoded) {
        const url = new URL(window.location.href);
        url.searchParams.set(URL_PARAM_KEY, encoded);
        return url.toString();
    }
    return window.location.href;
}

async function copyShareLink() {
    const url = getShareableURL();
    const btn = _appRoot.querySelector('#share-btn');
    const originalText = btn.textContent;

    try {
        await navigator.clipboard.writeText(url);
        btn.textContent = 'Copied!';
        btn.classList.add('success');
        console.log('[JetLag] Share link copied to clipboard');
    } catch (e) {
        // Fallback for older browsers or if clipboard API fails
        const textArea = document.createElement('textarea');
        textArea.value = url;
        textArea.style.position = 'fixed';
        textArea.style.left = '-9999px';
        document.body.appendChild(textArea);
        textArea.select();
        try {
            document.execCommand('copy');
            btn.textContent = 'Copied!';
            btn.classList.add('success');
        } catch (e2) {
            btn.textContent = 'Failed';
            console.warn('[JetLag] Could not copy to clipboard:', e2);
        }
        document.body.removeChild(textArea);
    }

    // Reset button after 2 seconds
    setTimeout(() => {
        btn.textContent = originalText;
        btn.classList.remove('success');
    }, 2000);
}

// ============ Local Storage ============

function saveToStorage() {
    const data = {
        homeTimezone: _appRoot.querySelector('#home-timezone').value,
        usualBedtime: _appRoot.querySelector('#usual-bedtime').value,
        usualWaketime: _appRoot.querySelector('#usual-waketime').value,
        daysBeforeStart: _appRoot.querySelector('#plan-start').value,
        flights: collectFlightData(),
        savedAt: new Date().toISOString(),
    };

    // Save to localStorage
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
        console.log('[JetLag] Saved to localStorage:', data.flights.length, 'flights');
    } catch (e) {
        console.warn('[JetLag] Could not save to localStorage:', e);
    }

    // Also update URL (debounced in the caller already for input events)
    saveToURL(data);
}

function loadFromStorage() {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (data) {
            const parsed = JSON.parse(data);
            console.log('[JetLag] Loaded from localStorage:', parsed.flights?.length, 'flights, saved at:', parsed.savedAt);
            return parsed;
        }
        console.log('[JetLag] No saved data found in localStorage');
        return null;
    } catch (e) {
        console.warn('[JetLag] Could not load from localStorage:', e);
        return null;
    }
}

function restoreSavedData(data) {
    // Restore profile
    if (data.homeTimezone) {
        _appRoot.querySelector('#home-timezone').value = data.homeTimezone;
    }
    if (data.usualBedtime) {
        _appRoot.querySelector('#usual-bedtime').value = data.usualBedtime;
    }
    if (data.usualWaketime) {
        _appRoot.querySelector('#usual-waketime').value = data.usualWaketime;
    }
    if (data.daysBeforeStart) {
        _appRoot.querySelector('#plan-start').value = data.daysBeforeStart;
    }

    // Restore flights
    if (data.flights && data.flights.length > 0) {
        data.flights.forEach((flight, index) => {
            addFlight(flight);
        });
    } else {
        addFlight();
    }
}

function showSavedIndicator(message = 'Restored') {
    const header = _appRoot.querySelector('#flights-section h2');
    if (header && !header.querySelector('.saved-indicator')) {
        const indicator = document.createElement('span');
        indicator.className = 'saved-indicator';
        indicator.textContent = message;
        header.appendChild(indicator);

        // Fade out after 3 seconds
        setTimeout(() => {
            indicator.style.transition = 'opacity 0.5s';
            indicator.style.opacity = '0';
            setTimeout(() => indicator.remove(), 500);
        }, 3000);
    }
}

function clearStorage() {
    try {
        localStorage.removeItem(STORAGE_KEY);
    } catch (e) {
        console.warn('Could not clear localStorage:', e);
    }
}

// ============ Flight Management ============

let flightCount = 0;

function addFlight(flightData = null) {
    const template = _appRoot.querySelector('#flight-template');
    const container = _appRoot.querySelector('#flights-container');

    const flightCard = template.content.cloneNode(true);
    const card = flightCard.querySelector('.flight-card');

    flightCount++;
    card.dataset.flightIndex = flightCount;
    card.querySelector('.flight-number').textContent = flightCount;

    // Populate timezone selects
    const tzSelects = card.querySelectorAll('select');
    tzSelects.forEach(select => {
        select.innerHTML = '<option value="">Select timezone...</option>';
        TIMEZONES.forEach(tz => {
            const option = document.createElement('option');
            option.value = tz.id;
            option.textContent = tz.name;
            option.dataset.offset = tz.offset;
            select.appendChild(option);
        });
    });

    // Set values from saved data or defaults
    if (flightData) {
        card.querySelector('.departure-airport').value = flightData.departureAirport || '';
        card.querySelector('.arrival-airport').value = flightData.arrivalAirport || '';
        card.querySelector('.departure-datetime').value = flightData.departureDateTime || '';
        card.querySelector('.departure-timezone').value = flightData.departureTimezone || '';
        card.querySelector('.arrival-datetime').value = flightData.arrivalDateTime || '';
        card.querySelector('.arrival-timezone').value = flightData.arrivalTimezone || '';
    } else {
        // Set default date/time
        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(9, 0, 0, 0);

        const arrivalTime = new Date(tomorrow);
        arrivalTime.setHours(arrivalTime.getHours() + 8);

        card.querySelector('.departure-datetime').value = formatDateTimeLocal(tomorrow);
        card.querySelector('.arrival-datetime').value = formatDateTimeLocal(arrivalTime);
    }

    // Auto-fill timezone from airport code
    const departureAirport = card.querySelector('.departure-airport');
    const arrivalAirport = card.querySelector('.arrival-airport');
    const departureTz = card.querySelector('.departure-timezone');
    const arrivalTz = card.querySelector('.arrival-timezone');

    departureAirport.addEventListener('blur', () => {
        const tz = getTimezoneFromAirport(departureAirport.value);
        if (tz) {
            departureTz.value = tz;
            saveToStorage();
        }
    });

    arrivalAirport.addEventListener('blur', () => {
        const tz = getTimezoneFromAirport(arrivalAirport.value);
        if (tz) {
            arrivalTz.value = tz;
            saveToStorage();
        }
    });

    // Remove flight button
    card.querySelector('.remove-flight').addEventListener('click', () => {
        card.remove();
        renumberFlights();
        saveToStorage();
    });

    container.appendChild(flightCard);
}

function renumberFlights() {
    const cards = _appRoot.querySelectorAll('.flight-card');
    cards.forEach((card, index) => {
        card.dataset.flightIndex = index + 1;
        card.querySelector('.flight-number').textContent = index + 1;
    });
    flightCount = cards.length;
}

function formatDateTimeLocal(date) {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    return `${year}-${month}-${day}T${hours}:${minutes}`;
}

function collectFlightData() {
    const flights = [];
    const cards = _appRoot.querySelectorAll('.flight-card');

    cards.forEach(card => {
        flights.push({
            departureAirport: card.querySelector('.departure-airport').value.toUpperCase(),
            arrivalAirport: card.querySelector('.arrival-airport').value.toUpperCase(),
            departureDateTime: card.querySelector('.departure-datetime').value,
            departureTimezone: card.querySelector('.departure-timezone').value,
            arrivalDateTime: card.querySelector('.arrival-datetime').value,
            arrivalTimezone: card.querySelector('.arrival-timezone').value,
        });
    });

    return flights;
}

function validateFlights(flights) {
    const errors = [];

    flights.forEach((flight, index) => {
        const num = index + 1;
        if (!flight.departureDateTime) {
            errors.push(`Flight ${num}: Departure date/time is required`);
        }
        if (!flight.departureTimezone) {
            errors.push(`Flight ${num}: Departure timezone is required`);
        }
        if (!flight.arrivalDateTime) {
            errors.push(`Flight ${num}: Arrival date/time is required`);
        }
        if (!flight.arrivalTimezone) {
            errors.push(`Flight ${num}: Arrival timezone is required`);
        }
    });

    return errors;
}

// ============ Plan Generation ============

function generatePlan() {
    const flights = collectFlightData();

    // Validate
    const errors = validateFlights(flights);
    if (errors.length > 0) {
        alert('Please fix the following:\n\n' + errors.join('\n'));
        return;
    }

    // Save before generating
    saveToStorage();

    // Collect user profile
    const config = {
        homeTimezone: _appRoot.querySelector('#home-timezone').value,
        usualBedtime: _appRoot.querySelector('#usual-bedtime').value,
        usualWaketime: _appRoot.querySelector('#usual-waketime').value,
        flights: flights,
        daysBeforeStart: parseInt(_appRoot.querySelector('#plan-start').value),
    };

    // Generate plan
    const plan = createJetLagPlan(config);

    if (plan.error) {
        alert('Error generating plan: ' + plan.error);
        return;
    }

    // Display results
    displayPlan(plan);
}

function displayPlan(plan) {
    const resultsSection = _appRoot.querySelector('#results-section');
    resultsSection.classList.remove('hidden');

    // Scroll to results
    resultsSection.scrollIntoView({ behavior: 'smooth' });

    // Update header with regenerate button
    const resultsCard = resultsSection;
    let header = resultsCard.querySelector('.results-header');
    if (!header) {
        const h2 = resultsCard.querySelector('h2');
        header = document.createElement('div');
        header.className = 'results-header';
        header.innerHTML = `<h2>${h2.innerHTML}</h2>`;
        h2.replaceWith(header);
    }

    // Add regenerate button if not present
    if (!header.querySelector('.btn-ghost')) {
        const regenBtn = document.createElement('button');
        regenBtn.type = 'button';
        regenBtn.className = 'btn btn-ghost btn-small';
        regenBtn.textContent = 'Regenerate';
        regenBtn.addEventListener('click', generatePlan);
        header.appendChild(regenBtn);
    }

    // Summary
    const summaryHtml = `
        <h3>Trip Summary</h3>
        <p>
            Traveling <strong>${plan.summary.direction}ward</strong> with a
            <strong>${plan.summary.totalShiftHours.toFixed(1)} hour</strong> time zone change.
        </p>
        <div class="summary-stats">
            <div class="stat">
                <div class="stat-value">${plan.summary.totalShiftHours.toFixed(1)}h</div>
                <div class="stat-label">Time Shift</div>
            </div>
            <div class="stat">
                <div class="stat-value">${plan.summary.daysToAdjust}</div>
                <div class="stat-label">Days to Adjust</div>
            </div>
            <div class="stat">
                <div class="stat-value">${plan.summary.direction === 'east' ? '&#8599;' : '&#8598;'}</div>
                <div class="stat-label">${plan.summary.direction === 'east' ? 'Eastward' : 'Westward'}</div>
            </div>
        </div>
    `;
    _appRoot.querySelector('#plan-summary').innerHTML = summaryHtml;

    // Timeline view
    renderTimeline(plan.schedule);

    // Daily view
    renderDailyView(plan.schedule);

    // Shifter view (Timeshifter-style)
    renderShifterView(plan.schedule, plan.summary);
}

// ============ Timeline Rendering ============

function renderTimeline(schedule) {
    const container = _appRoot.querySelector('#timeline-view');

    const legendHtml = `
        <div class="legend">
            <div class="legend-item"><div class="legend-color" style="background: var(--jlp-sleep)"></div> Sleep</div>
            <div class="legend-item"><div class="legend-color" style="background: var(--jlp-light-seek)"></div> Seek Light</div>
            <div class="legend-item"><div class="legend-color" style="background: var(--jlp-light-avoid); border: 2px dashed var(--jlp-text-muted)"></div> Avoid Light</div>
            <div class="legend-item"><div class="legend-color" style="background: var(--jlp-caffeine)"></div> Caffeine OK</div>
            <div class="legend-item"><div class="legend-color" style="background: var(--jlp-melatonin)"></div> Melatonin</div>
            <div class="legend-item"><div class="legend-color" style="background: var(--jlp-nap)"></div> Nap</div>
            <div class="legend-item"><div class="legend-color" style="background: var(--jlp-flight)"></div> Flight</div>
        </div>
    `;

    let html = legendHtml;

    // Get current time for "Now" indicator
    const now = new Date();
    const todayStr = now.toDateString();
    const currentMins = now.getHours() * 60 + now.getMinutes();

    schedule.forEach(day => {
        const dateStr = day.date.toLocaleDateString('en-US', {
            weekday: 'short',
            month: 'short',
            day: 'numeric',
        });

        // Check if this is today
        const isToday = day.date.toDateString() === todayStr;

        // Render horizontal timeline with dynamic height for lanes
        const timelineResult = renderTimelineEvents(day.events);

        html += `
            <div class="timeline-day${isToday ? ' timeline-day-today' : ''}">
                <div class="timeline-day-header">
                    <span class="timeline-day-title">${day.dayLabel}${isToday ? ' <span class="today-badge">Today</span>' : ''}</span>
                    <span class="timeline-day-date">${dateStr}</span>
                </div>
                <div class="timeline-bar" style="height: ${timelineResult.height}px;">
                    ${timelineResult.html}
                    ${isToday ? renderNowIndicator(currentMins) : ''}
                </div>
                <div class="timeline-vertical">
                    ${renderVerticalTimeline(day.events, isToday, currentMins)}
                </div>
            </div>
        `;
    });

    container.innerHTML = html;
}

function renderNowIndicator(currentMins) {
    const position = (currentMins / 1440) * 100;
    const timeStr = formatTimeDisplay(currentMins);
    return `
        <div class="timeline-now" style="left: ${position}%;">
            <div class="timeline-now-line"></div>
            <div class="timeline-now-label">Now ${timeStr}</div>
        </div>
    `;
}

/**
 * Assign events to lanes to handle overlaps.
 * Returns events with a 'lane' property (0, 1, 2, etc.)
 */
function assignLanes(events) {
    // Normalize times and sort by start
    const normalized = events.map(e => {
        let start = ((e.startTime % 1440) + 1440) % 1440;
        let end = ((e.endTime % 1440) + 1440) % 1440;
        // Handle overnight events
        if (e.type === 'sleep' && end < start) {
            end += 1440;
        }
        return { ...e, normStart: start, normEnd: end };
    }).sort((a, b) => a.normStart - b.normStart);

    // Assign lanes - greedy algorithm
    const lanes = []; // Each lane has an 'endTime' of the last event in it

    normalized.forEach(event => {
        // Find the first lane where this event fits (doesn't overlap)
        let assignedLane = -1;
        for (let i = 0; i < lanes.length; i++) {
            if (event.normStart >= lanes[i]) {
                assignedLane = i;
                lanes[i] = event.normEnd;
                break;
            }
        }
        // If no lane fits, create a new one
        if (assignedLane === -1) {
            assignedLane = lanes.length;
            lanes.push(event.normEnd);
        }
        event.lane = assignedLane;
    });

    return { events: normalized, laneCount: lanes.length };
}

function renderTimelineEvents(events) {
    const { events: laneEvents, laneCount } = assignLanes(events);

    // Calculate lane height - shrink if many lanes
    const laneHeight = laneCount <= 2 ? 24 : Math.max(16, 48 / laneCount);
    const totalHeight = laneCount * laneHeight + 8; // 8px padding

    let html = '';

    laneEvents.forEach(event => {
        let startMins = event.normStart;
        let endMins = event.normEnd;

        // Handle overnight events (already normalized, but need to render in two parts if > 1440)
        if (endMins > 1440) {
            // Evening part
            const eveningWidth = ((1440 - startMins) / 1440) * 100;
            const eveningLeft = (startMins / 1440) * 100;
            const top = 4 + event.lane * laneHeight;
            html += `<div class="timeline-event ${event.type}" style="left: ${eveningLeft}%; width: ${eveningWidth}%; top: ${top}px; height: ${laneHeight - 2}px;" title="${event.description}"></div>`;

            // Morning part (next day, but we show it wrapping)
            const morningWidth = ((endMins - 1440) / 1440) * 100;
            html += `<div class="timeline-event ${event.type}" style="left: 0%; width: ${morningWidth}%; top: ${top}px; height: ${laneHeight - 2}px;" title="${event.description}"></div>`;
            return;
        }

        const left = (startMins / 1440) * 100;
        const width = Math.max(((endMins - startMins) / 1440) * 100, 1.5);
        const top = 4 + event.lane * laneHeight;

        const label = getEventLabel(event.type);
        const showLabel = width > 8 && laneHeight >= 20;
        html += `<div class="timeline-event ${event.type}" style="left: ${left}%; width: ${width}%; top: ${top}px; height: ${laneHeight - 2}px;" title="${event.description}">${showLabel ? label : ''}</div>`;
    });

    // Return HTML with dynamic height style
    return { html, height: totalHeight };
}

function renderVerticalTimeline(events, isToday = false, currentMins = 0) {
    // Categorize events: active now, upcoming, past
    const categorized = events.map(event => {
        const start = ((event.startTime % 1440) + 1440) % 1440;
        let end = ((event.endTime % 1440) + 1440) % 1440;
        // Handle overnight
        if (event.type === 'sleep' && end < start) {
            end += 1440;
        }
        const adjustedCurrent = currentMins < start && end > 1440 ? currentMins + 1440 : currentMins;

        let status = 'upcoming';
        if (isToday) {
            if (adjustedCurrent >= start && adjustedCurrent < end) {
                status = 'active';
            } else if (adjustedCurrent >= end) {
                status = 'past';
            }
        }
        return { ...event, normStart: start, normEnd: end, status };
    });

    // Sort: active first, then upcoming by time, then past
    const sorted = categorized.sort((a, b) => {
        const statusOrder = { active: 0, upcoming: 1, past: 2 };
        if (statusOrder[a.status] !== statusOrder[b.status]) {
            return statusOrder[a.status] - statusOrder[b.status];
        }
        return a.normStart - b.normStart;
    });

    let html = '';
    let lastStatus = null;

    sorted.forEach(event => {
        // Add section headers
        if (isToday && event.status !== lastStatus) {
            if (event.status === 'active') {
                html += `<div class="timeline-section-header active-header">🔴 Happening Now</div>`;
            } else if (event.status === 'upcoming' && lastStatus === 'active') {
                html += `<div class="timeline-section-header">Coming Up</div>`;
            } else if (event.status === 'past' && lastStatus !== 'past') {
                html += `<div class="timeline-section-header past-header">Earlier Today</div>`;
            }
            lastStatus = event.status;
        }

        const startTime = formatTimeDisplay(event.startTime);
        const endTime = formatTimeDisplay(event.endTime);
        const timeRange = event.type === 'melatonin' ? startTime : `${startTime} - ${endTime}`;
        const label = getEventLabel(event.type);

        const activeClass = event.status === 'active' ? ' active-now' : '';
        const pastClass = event.status === 'past' ? ' past-event' : '';

        html += `
            <div class="timeline-vertical-event ${event.type}${activeClass}${pastClass}">
                <div class="timeline-vertical-time">${timeRange}</div>
                <div>
                    <div class="timeline-vertical-label">${label}</div>
                    <div class="timeline-vertical-desc">${event.description}</div>
                </div>
            </div>
        `;
    });

    // Add Now indicator if no active events
    if (isToday && !sorted.some(e => e.status === 'active')) {
        const timeStr = formatTimeDisplay(currentMins);
        html = `
            <div class="timeline-vertical-now standalone">
                <div class="timeline-vertical-now-label">Now ${timeStr}</div>
            </div>
        ` + html;
    }

    return html;
}

// ============ Shifter View (Timeshifter-style) ============

function renderShifterView(schedule, summary) {
    const container = _appRoot.querySelector('#shifter-view');

    // Get current time for "Now" indicator
    const now = new Date();
    const todayStr = now.toDateString();
    const currentMins = now.getHours() * 60 + now.getMinutes();

    // Preprocess: collect overnight continuations from each day into the next
    const dayEvents = schedule.map(day => [...day.events]);
    for (let i = 0; i < dayEvents.length; i++) {
        dayEvents[i].forEach(event => {
            const start = ((event.startTime % 1440) + 1440) % 1440;
            const end = ((event.endTime % 1440) + 1440) % 1440;
            if (end > 0 && end < start && i + 1 < dayEvents.length) {
                // Event crosses midnight — add continuation to next day
                dayEvents[i + 1].push({
                    ...event,
                    startTime: 0,
                    endTime: end,
                    _continuation: true, // rendering flag only
                });
            }
        });
    }

    let html = '<div class="shifter-container">';

    schedule.forEach((day, dayIndex) => {
        const dateStr = day.date.toLocaleDateString('en-US', {
            weekday: 'short',
            month: 'short',
            day: 'numeric',
        });
        const isToday = day.date.toDateString() === todayStr;

        // Use preprocessed events (includes continuations from previous day)
        const events = dayEvents[dayIndex].sort((a, b) => {
            const aStart = ((a.startTime % 1440) + 1440) % 1440;
            const bStart = ((b.startTime % 1440) + 1440) % 1440;
            return aStart - bStart;
        });

        // Each day spans midnight to midnight — find the active range
        let minTime = 1440, maxTime = 0;
        events.forEach(e => {
            let start = ((e.startTime % 1440) + 1440) % 1440;
            let end = ((e.endTime % 1440) + 1440) % 1440;
            if (end < start) end = 1440; // Clamp overnight at midnight (continuation is on next day)
            minTime = Math.min(minTime, start);
            maxTime = Math.max(maxTime, end);
        });

        // Round to nearest hour, always end at midnight
        const startHour = Math.floor(minTime / 60);
        const endHour = 24; // Always end at midnight
        const hours = [];
        for (let h = startHour; h <= endHour; h++) {
            hours.push(h % 24);
        }

        // Date header
        html += `
            <div class="shifter-day${isToday ? ' shifter-day-today' : ''}">
                <div class="shifter-date-header">
                    <span class="shifter-date">${dateStr}</span>
                    <span class="shifter-label">${day.dayLabel}</span>
                    ${isToday ? '<span class="shifter-now-badge">Now</span>' : ''}
                </div>
                <div class="shifter-timeline">
                    <div class="shifter-hours-left">
                        ${hours.map(h => `<div class="shifter-hour">${formatHour(h)}</div>`).join('')}
                    </div>
                    <div class="shifter-track" data-start-hour="${startHour}" data-end-hour="${endHour}">
                        ${renderShifterEvents(events, startHour, endHour, isToday, currentMins)}
                        ${isToday ? renderShifterNowLine(currentMins, startHour, endHour) : ''}
                    </div>
                    <div class="shifter-hours-right">
                        ${hours.map(h => `<div class="shifter-hour">${formatHour(h)}</div>`).join('')}
                    </div>
                </div>
            </div>
        `;
    });

    html += '</div>';

    // Add event detail popup
    html += `
        <div class="shifter-popup" id="shifter-popup">
            <div class="shifter-popup-content">
                <div class="shifter-popup-header">
                    <span class="shifter-popup-icon"></span>
                    <span class="shifter-popup-title"></span>
                </div>
                <div class="shifter-popup-time"></div>
                <div class="shifter-popup-desc"></div>
            </div>
        </div>
    `;

    container.innerHTML = html;

    // Add click handlers for events
    container.querySelectorAll('.shifter-event').forEach(el => {
        el.addEventListener('click', (e) => {
            showShifterPopup(el);
            e.stopPropagation();
        });
    });

    // Close popup when clicking outside
    container.addEventListener('click', () => {
        hideShifterPopup();
    });
}

function renderShifterEvents(events, startHour, endHour, isToday, currentMins) {
    const totalMins = (endHour - startHour) * 60;
    const startMins = startHour * 60;

    // Assign columns for overlapping events
    const { events: laneEvents, laneCount } = assignShifterLanes(events, startHour, endHour);

    let html = '';

    laneEvents.forEach(event => {
        let evStart = ((event.startTime % 1440) + 1440) % 1440;
        let evEnd = ((event.endTime % 1440) + 1440) % 1440;

        // Handle overnight events - clamp at midnight (continuation on next day)
        if (evEnd < evStart) {
            evEnd = 1440;
        }

        // Clamp to display range
        evStart = Math.max(evStart, startMins);
        evEnd = Math.min(evEnd, endHour * 60);

        const top = ((evStart - startMins) / totalMins) * 100;
        const height = Math.max(((evEnd - evStart) / totalMins) * 100, 3);

        // Calculate horizontal position based on lane
        const laneWidth = 100 / laneCount;
        const left = event.lane * laneWidth;
        const width = laneWidth - 4; // Gap between lanes

        const icon = getShifterIcon(event.type);
        const isActive = isToday && currentMins >= evStart && currentMins < evEnd;

        // Build data attributes, including timezone info for flights
        let dataAttrs = `data-type="${event.type}"`;
        dataAttrs += ` data-start="${formatTimeDisplay(event.startTime)}"`;
        dataAttrs += ` data-end="${formatTimeDisplay(event.endTime)}"`;
        dataAttrs += ` data-desc="${escapeHtml(event.description)}"`;

        if (event.type === 'flight' && event.flight) {
            dataAttrs += ` data-dep-tz="${event.departureTimezone || ''}"`;
            dataAttrs += ` data-arr-tz="${event.arrivalTimezone || ''}"`;
            dataAttrs += ` data-arr-time="${event.arrivalLocalTime || ''}"`;
            dataAttrs += ` data-duration="${event.durationMins || 0}"`;
            dataAttrs += ` data-tz-shift="${event.timezoneShift || 0}"`;
        }

        html += `
            <div class="shifter-event shifter-event-${event.type}${isActive ? ' active' : ''}"
                 style="top: ${top}%; height: ${height}%; left: ${left}%; width: ${width}%;"
                 ${dataAttrs}>
                <span class="shifter-event-icon">${icon}</span>
            </div>
        `;
    });

    return html;
}

function assignShifterLanes(events, startHour, endHour) {
    const startMins = startHour * 60;
    const endMins = endHour * 60;

    const normalized = events.map(e => {
        let start = ((e.startTime % 1440) + 1440) % 1440;
        let end = ((e.endTime % 1440) + 1440) % 1440;
        if (end < start) end = 1440; // Clamp at midnight (continuation on next day)
        // Clamp to range
        start = Math.max(start, startMins);
        end = Math.min(end, endMins);
        return { ...e, normStart: start, normEnd: end };
    }).filter(e => e.normEnd > e.normStart)
      .sort((a, b) => a.normStart - b.normStart);

    const lanes = [];

    normalized.forEach(event => {
        let assignedLane = -1;
        for (let i = 0; i < lanes.length; i++) {
            if (event.normStart >= lanes[i]) {
                assignedLane = i;
                lanes[i] = event.normEnd;
                break;
            }
        }
        if (assignedLane === -1) {
            assignedLane = lanes.length;
            lanes.push(event.normEnd);
        }
        event.lane = assignedLane;
    });

    return { events: normalized, laneCount: Math.max(1, lanes.length) };
}

function renderShifterNowLine(currentMins, startHour, endHour) {
    const totalMins = (endHour - startHour) * 60;
    const startMins = startHour * 60;

    if (currentMins < startMins || currentMins > endHour * 60) {
        return '';
    }

    const top = ((currentMins - startMins) / totalMins) * 100;

    return `
        <div class="shifter-now-line" style="top: ${top}%;">
            <div class="shifter-now-dot"></div>
            <div class="shifter-now-line-bar"></div>
            <div class="shifter-now-time">${formatTimeDisplay(currentMins)}</div>
        </div>
    `;
}

function getShifterIcon(type) {
    const icons = {
        'sleep': '😴',
        'light-seek': '☀️',
        'light-avoid': '🕶️',
        'caffeine': '☕',
        'melatonin': '💊',
        'nap': '💤',
        'flight': '✈️',
    };
    return icons[type] || '•';
}

function formatHour(hour) {
    if (hour === 0 || hour === 24) return '12am';
    if (hour === 12) return '12pm';
    if (hour < 12) return `${hour}am`;
    return `${hour - 12}pm`;
}

function escapeHtml(str) {
    if (!str) return '';
    return str.replace(/&/g, '&amp;')
              .replace(/</g, '&lt;')
              .replace(/>/g, '&gt;')
              .replace(/"/g, '&quot;')
              .replace(/'/g, '&#39;');
}

function formatTimezoneShort(tz) {
    if (!tz) return '';
    // Extract short name from timezone ID like "Pacific/Honolulu" -> "HST" or just show offset
    const parts = tz.split('/');
    return parts[parts.length - 1].replace(/_/g, ' ');
}

function showShifterPopup(element) {
    const popup = _appRoot.querySelector('#shifter-popup');
    const type = element.dataset.type;
    const start = element.dataset.start;
    const end = element.dataset.end;
    const desc = element.dataset.desc;

    popup.querySelector('.shifter-popup-icon').textContent = getShifterIcon(type);
    popup.querySelector('.shifter-popup-title').textContent = getEventLabelText(type);

    // Build time display with timezone info for flights
    let timeText = '';
    if (type === 'flight') {
        const depTz = element.dataset.depTz;
        const arrTz = element.dataset.arrTz;
        const arrTime = element.dataset.arrTime;
        const duration = parseInt(element.dataset.duration) || 0;
        const tzShift = parseInt(element.dataset.tzShift) || 0;

        const durationHrs = Math.floor(duration / 60);
        const durationMins = duration % 60;
        const durationStr = durationMins > 0 ? `${durationHrs}h ${durationMins}m` : `${durationHrs}h`;

        timeText = `Depart: ${start} (${formatTimezoneShort(depTz)})\n`;
        timeText += `Arrive: ${arrTime} (${formatTimezoneShort(arrTz)})\n`;
        timeText += `Duration: ${durationStr}`;

        if (tzShift !== 0) {
            const sign = tzShift > 0 ? '+' : '';
            timeText += `\nTimezone: ${sign}${tzShift}h`;
        }
    } else if (type === 'melatonin') {
        timeText = start;
    } else {
        timeText = `${start} - ${end}`;
    }

    popup.querySelector('.shifter-popup-time').innerText = timeText;
    popup.querySelector('.shifter-popup-desc').textContent = desc;

    popup.classList.add('visible');

    // Position popup near the element
    const rect = element.getBoundingClientRect();
    const popupContent = popup.querySelector('.shifter-popup-content');

    // Position below the element, but ensure it stays in viewport
    let top = rect.bottom + 10;
    let left = Math.max(10, rect.left - 50);

    // Check if popup would go off bottom of screen
    const popupHeight = 150; // Estimate
    if (top + popupHeight > window.innerHeight) {
        top = rect.top - popupHeight - 10;
    }

    // Check if popup would go off right of screen
    const popupWidth = 280;
    if (left + popupWidth > window.innerWidth) {
        left = window.innerWidth - popupWidth - 10;
    }

    popupContent.style.top = `${top}px`;
    popupContent.style.left = `${left}px`;
}

function hideShifterPopup() {
    const popup = _appRoot.querySelector('#shifter-popup');
    popup.classList.remove('visible');
}

function getEventLabel(type) {
    const labels = {
        'sleep': '😴 Sleep',
        'light-seek': '☀️ Seek Light',
        'light-avoid': '🕶️ Avoid Light',
        'caffeine': '☕ Caffeine OK',
        'melatonin': '💊 Melatonin',
        'nap': '💤 Nap',
        'flight': '✈️ Flight',
    };
    return labels[type] || type;
}

function getEventLabelText(type) {
    const labels = {
        'sleep': 'Sleep',
        'light-seek': 'Seek Light',
        'light-avoid': 'Avoid Light',
        'caffeine': 'Caffeine OK',
        'melatonin': 'Melatonin',
        'nap': 'Nap',
        'flight': 'Flight',
    };
    return labels[type] || type;
}

// ============ Daily View Rendering ============

function renderDailyView(schedule) {
    const container = _appRoot.querySelector('#daily-view');
    let html = '';

    schedule.forEach(day => {
        const dateStr = day.date.toLocaleDateString('en-US', {
            weekday: 'long',
            month: 'long',
            day: 'numeric',
        });

        html += `
            <div class="daily-schedule">
                <div class="daily-header">${day.dayLabel} - ${dateStr}</div>
        `;

        // Sort events by start time
        const sortedEvents = [...day.events].sort((a, b) => {
            const aTime = ((a.startTime % 1440) + 1440) % 1440;
            const bTime = ((b.startTime % 1440) + 1440) % 1440;
            return aTime - bTime;
        });

        sortedEvents.forEach(event => {
            const startTime = formatTimeDisplay(event.startTime);
            const endTime = formatTimeDisplay(event.endTime);
            const timeRange = event.type === 'melatonin'
                ? startTime
                : `${startTime} - ${endTime}`;

            html += `
                <div class="daily-item ${event.type}">
                    <div class="daily-time">${timeRange}</div>
                    <div class="daily-activity">
                        <span class="activity-type ${event.type}">${getEventLabel(event.type)}</span>
                        <div class="activity-description">${event.description}</div>
                    </div>
                </div>
            `;
        });

        html += '</div>';
    });

    container.innerHTML = html;
}

function formatTimeDisplay(minutes) {
    const normalizedMinutes = ((minutes % 1440) + 1440) % 1440;
    const hours = Math.floor(normalizedMinutes / 60);
    const mins = Math.round(normalizedMinutes % 60);
    const ampm = hours >= 12 ? 'PM' : 'AM';
    const displayHours = hours % 12 || 12;
    return `${displayHours}:${mins.toString().padStart(2, '0')} ${ampm}`;
}

function switchTab(tabName) {
    _appRoot.querySelectorAll('.tab-btn').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.tab === tabName);
    });

    _appRoot.querySelectorAll('.tab-content').forEach(content => {
        content.classList.toggle('active', content.id === `${tabName}-view`);
    });
}

